// The synthetic ensures has the shape `H ==> det_proc_push_thread_equal(...)`
// where H is the conjunction of `proc_push_thread`'s per-run ensures.  Inside
// a Verus proof body those conjuncts are NOT free hypotheses — they sit on the
// antecedent side of an implication.  Guard the body with a proof-mode `if`
// whose condition is the full antecedent: inside the branch every conjunct of
// H is a path-condition fact so the cross-run equalities and the helper
// lemmas can fire.  On the `else` path the implication is vacuous.
if ({
    &&& post1_proc_perm@.is_init()
    &&& post1_proc_perm@.addr() == proc_ptr
    &&& post1_proc_perm@.value().owning_container =~= pre_proc_perm@.value().owning_container
    &&& post1_proc_perm@.value().rev_ptr =~= pre_proc_perm@.value().rev_ptr
    &&& post1_proc_perm@.value().pcid =~= pre_proc_perm@.value().pcid
    &&& post1_proc_perm@.value().ioid =~= pre_proc_perm@.value().ioid
    &&& post1_proc_perm@.value().parent =~= pre_proc_perm@.value().parent
    &&& post1_proc_perm@.value().parent_rev_ptr =~= pre_proc_perm@.value().parent_rev_ptr
    &&& post1_proc_perm@.value().children =~= pre_proc_perm@.value().children
    &&& post1_proc_perm@.value().uppertree_seq =~= pre_proc_perm@.value().uppertree_seq
    &&& post1_proc_perm@.value().subtree_set =~= pre_proc_perm@.value().subtree_set
    &&& post1_proc_perm@.value().depth =~= pre_proc_perm@.value().depth
    &&& post1_proc_perm@.value().dmd_paging_mode =~= pre_proc_perm@.value().dmd_paging_mode
    &&& post1_proc_perm@.value().owned_threads.wf()
    &&& post1_proc_perm@.value().owned_threads@
            =~= pre_proc_perm@.value().owned_threads@.push(*thread_ptr)
    &&& post1_proc_perm@.value().owned_threads.len()
            == pre_proc_perm@.value().owned_threads.len() + 1
    &&& (forall|v: ThreadPtr|
            #![auto]
            pre_proc_perm@.value().owned_threads@.contains(v) ==>
                pre_proc_perm@.value().owned_threads.get_node_ref(v)
                    == post1_proc_perm@.value().owned_threads.get_node_ref(v))
    &&& post1_proc_perm@.value().owned_threads.get_node_ref(*thread_ptr) == r1
    &&& post1_proc_perm@.value().owned_threads.unique()
    &&& post2_proc_perm@.is_init()
    &&& post2_proc_perm@.addr() == proc_ptr
    &&& post2_proc_perm@.value().owning_container =~= pre_proc_perm@.value().owning_container
    &&& post2_proc_perm@.value().rev_ptr =~= pre_proc_perm@.value().rev_ptr
    &&& post2_proc_perm@.value().pcid =~= pre_proc_perm@.value().pcid
    &&& post2_proc_perm@.value().ioid =~= pre_proc_perm@.value().ioid
    &&& post2_proc_perm@.value().parent =~= pre_proc_perm@.value().parent
    &&& post2_proc_perm@.value().parent_rev_ptr =~= pre_proc_perm@.value().parent_rev_ptr
    &&& post2_proc_perm@.value().children =~= pre_proc_perm@.value().children
    &&& post2_proc_perm@.value().uppertree_seq =~= pre_proc_perm@.value().uppertree_seq
    &&& post2_proc_perm@.value().subtree_set =~= pre_proc_perm@.value().subtree_set
    &&& post2_proc_perm@.value().depth =~= pre_proc_perm@.value().depth
    &&& post2_proc_perm@.value().dmd_paging_mode =~= pre_proc_perm@.value().dmd_paging_mode
    &&& post2_proc_perm@.value().owned_threads.wf()
    &&& post2_proc_perm@.value().owned_threads@
            =~= pre_proc_perm@.value().owned_threads@.push(*thread_ptr)
    &&& post2_proc_perm@.value().owned_threads.len()
            == pre_proc_perm@.value().owned_threads.len() + 1
    &&& (forall|v: ThreadPtr|
            #![auto]
            pre_proc_perm@.value().owned_threads@.contains(v) ==>
                pre_proc_perm@.value().owned_threads.get_node_ref(v)
                    == post2_proc_perm@.value().owned_threads.get_node_ref(v))
    &&& post2_proc_perm@.value().owned_threads.get_node_ref(*thread_ptr) == r2
    &&& post2_proc_perm@.value().owned_threads.unique()
}) {
    // ---------- Seq::push axioms -------------------------------------------
    seq_push_lemma::<ThreadPtr>();

    // ---------- owned_threads view equality --------------------------------
    lemma_owned_threads_view_eq(
        pre_proc_perm@.value().owned_threads,
        *thread_ptr,
        post1_proc_perm@.value().owned_threads,
        post2_proc_perm@.value().owned_threads,
    );
    assert(post1_proc_perm@.value().owned_threads@
        =~= post2_proc_perm@.value().owned_threads@);
    assert(post1_proc_perm@.value().owned_threads.view()
        == post2_proc_perm@.value().owned_threads.view());

    // ---------- Cross-run get_node_ref alignment over pre's threads --------
    lemma_get_node_ref_aligned_threadptr(
        pre_proc_perm@.value().owned_threads,
        post1_proc_perm@.value().owned_threads,
        post2_proc_perm@.value().owned_threads,
    );

    // ---------- is_init / addr ---------------------------------------------
    assert(post1_proc_perm@.is_init());
    assert(post2_proc_perm@.is_init());
    assert(post1_proc_perm@.is_init() == post2_proc_perm@.is_init());
    assert(post1_proc_perm@.addr() == proc_ptr);
    assert(post2_proc_perm@.addr() == proc_ptr);
    assert(post1_proc_perm@.addr() == post2_proc_perm@.addr());

    // ---------- Field-by-field equalities via `pre` ------------------------

    // owning_container
    assert(post1_proc_perm@.value().owning_container
        =~= pre_proc_perm@.value().owning_container);
    assert(post2_proc_perm@.value().owning_container
        =~= pre_proc_perm@.value().owning_container);
    assert(post1_proc_perm@.value().owning_container
        == post2_proc_perm@.value().owning_container);

    // rev_ptr
    assert(post1_proc_perm@.value().rev_ptr =~= pre_proc_perm@.value().rev_ptr);
    assert(post2_proc_perm@.value().rev_ptr =~= pre_proc_perm@.value().rev_ptr);
    assert(post1_proc_perm@.value().rev_ptr == post2_proc_perm@.value().rev_ptr);

    // pcid
    assert(post1_proc_perm@.value().pcid =~= pre_proc_perm@.value().pcid);
    assert(post2_proc_perm@.value().pcid =~= pre_proc_perm@.value().pcid);
    assert(post1_proc_perm@.value().pcid == post2_proc_perm@.value().pcid);

    // ioid
    assert(post1_proc_perm@.value().ioid =~= pre_proc_perm@.value().ioid);
    assert(post2_proc_perm@.value().ioid =~= pre_proc_perm@.value().ioid);
    assert(post1_proc_perm@.value().ioid == post2_proc_perm@.value().ioid);

    // parent
    assert(post1_proc_perm@.value().parent =~= pre_proc_perm@.value().parent);
    assert(post2_proc_perm@.value().parent =~= pre_proc_perm@.value().parent);
    assert(post1_proc_perm@.value().parent == post2_proc_perm@.value().parent);

    // parent_rev_ptr
    assert(post1_proc_perm@.value().parent_rev_ptr
        =~= pre_proc_perm@.value().parent_rev_ptr);
    assert(post2_proc_perm@.value().parent_rev_ptr
        =~= pre_proc_perm@.value().parent_rev_ptr);
    assert(post1_proc_perm@.value().parent_rev_ptr
        == post2_proc_perm@.value().parent_rev_ptr);

    // children
    assert(post1_proc_perm@.value().children =~= pre_proc_perm@.value().children);
    assert(post2_proc_perm@.value().children =~= pre_proc_perm@.value().children);
    assert(post1_proc_perm@.value().children == post2_proc_perm@.value().children);
    assert(post1_proc_perm@.value().children.view()
        == post2_proc_perm@.value().children.view());

    // uppertree_seq
    assert(post1_proc_perm@.value().uppertree_seq
        =~= pre_proc_perm@.value().uppertree_seq);
    assert(post2_proc_perm@.value().uppertree_seq
        =~= pre_proc_perm@.value().uppertree_seq);
    assert(post1_proc_perm@.value().uppertree_seq@
        =~= post2_proc_perm@.value().uppertree_seq@);

    // subtree_set
    assert(post1_proc_perm@.value().subtree_set
        =~= pre_proc_perm@.value().subtree_set);
    assert(post2_proc_perm@.value().subtree_set
        =~= pre_proc_perm@.value().subtree_set);
    assert(post1_proc_perm@.value().subtree_set@
        =~= post2_proc_perm@.value().subtree_set@);

    // depth
    assert(post1_proc_perm@.value().depth =~= pre_proc_perm@.value().depth);
    assert(post2_proc_perm@.value().depth =~= pre_proc_perm@.value().depth);
    assert(post1_proc_perm@.value().depth == post2_proc_perm@.value().depth);

    // dmd_paging_mode
    assert(post1_proc_perm@.value().dmd_paging_mode
        =~= pre_proc_perm@.value().dmd_paging_mode);
    assert(post2_proc_perm@.value().dmd_paging_mode
        =~= pre_proc_perm@.value().dmd_paging_mode);
    assert(post1_proc_perm@.value().dmd_paging_mode
        == post2_proc_perm@.value().dmd_paging_mode);

    // ---------- Surface r1 / r2 hooks --------------------------------------
    assert(post1_proc_perm@.value().owned_threads@
        == pre_proc_perm@.value().owned_threads@.push(*thread_ptr));
    assert(post2_proc_perm@.value().owned_threads@
        == pre_proc_perm@.value().owned_threads@.push(*thread_ptr));
    assert(post1_proc_perm@.value().owned_threads@
        == post2_proc_perm@.value().owned_threads@);
    assert(post1_proc_perm@.value().owned_threads.wf());
    assert(post2_proc_perm@.value().owned_threads.wf());
    assert(post1_proc_perm@.value().owned_threads.unique());
    assert(post2_proc_perm@.value().owned_threads.unique());
    assert(post1_proc_perm@.value().owned_threads.get_node_ref(*thread_ptr) == r1);
    assert(post2_proc_perm@.value().owned_threads.get_node_ref(*thread_ptr) == r2);
}

helper_lemmas:
// Functional-uniqueness for the relational `forall|v|` ensures conjunct
//   `forall|v| pre@.contains(v) ==> pre.get_node_ref(v) == postN.get_node_ref(v)`.
// The two ensures (one for post1, one for post2) have disjoint auto-triggers
// (each forall fires on its own `postN.get_node_ref(v)`), so z3 never picks
// a common instance.  This lemma chains them through `pre.get_node_ref(v)`
// and exposes the result under a single forall whose explicit trigger
// mentions BOTH posts, which is exactly the term shape needed downstream.
proof fn lemma_get_node_ref_aligned_threadptr(
    pre: StaticLinkedList<ThreadPtr, MAX_NUM_THREADS_PER_PROC>,
    post1: StaticLinkedList<ThreadPtr, MAX_NUM_THREADS_PER_PROC>,
    post2: StaticLinkedList<ThreadPtr, MAX_NUM_THREADS_PER_PROC>,
)
    requires
        forall|v: ThreadPtr|
            #![auto]
            pre@.contains(v) ==> pre.get_node_ref(v) == post1.get_node_ref(v),
        forall|v: ThreadPtr|
            #![auto]
            pre@.contains(v) ==> pre.get_node_ref(v) == post2.get_node_ref(v),
    ensures
        forall|v: ThreadPtr|
            #![trigger post1.get_node_ref(v), post2.get_node_ref(v)]
            pre@.contains(v) ==> post1.get_node_ref(v) == post2.get_node_ref(v),
{
    assert forall|v: ThreadPtr|
        #![trigger post1.get_node_ref(v), post2.get_node_ref(v)]
        pre@.contains(v) implies post1.get_node_ref(v) == post2.get_node_ref(v)
    by {
        assert(pre.get_node_ref(v) == post1.get_node_ref(v));
        assert(pre.get_node_ref(v) == post2.get_node_ref(v));
    }
}

// View extensionality on `owned_threads`: both runs push the same `*thread_ptr`
// onto the same `pre.owned_threads@`, so the per-run `=~=` ensures collapse
// to `==` via Seq::ext_equal.
proof fn lemma_owned_threads_view_eq(
    pre: StaticLinkedList<ThreadPtr, MAX_NUM_THREADS_PER_PROC>,
    new_value: ThreadPtr,
    post1: StaticLinkedList<ThreadPtr, MAX_NUM_THREADS_PER_PROC>,
    post2: StaticLinkedList<ThreadPtr, MAX_NUM_THREADS_PER_PROC>,
)
    requires
        post1@ =~= pre@.push(new_value),
        post2@ =~= pre@.push(new_value),
    ensures
        post1@ == post2@,
        post1.view() == post2.view(),
{
    assert(post1@ =~= post2@);
    assert(post1.view() =~= post2.view());
}
